import type { CalendarData } from "@/shared/types";

const CALENDAR_2024 =
  "";
const CALENDAR_2025 =
  "";
const CALENDAR_2026 =
  "";

const RAW: Record<number, string> = {
  2024: CALENDAR_2024,
  2025: CALENDAR_2025,
  2026: CALENDAR_2026,
};

function parseRaw(year: number, digits: string): CalendarData {
  const data = new Map<string, number>();
  const start = new Date(year, 0, 1);
  for (let i = 0; i < digits.length && i < 366; i++) {
    const d = new Date(start);
    d.setDate(d.getDate() + i);
    const ch = digits[i];
    if (ch == null) continue;
    const code = parseInt(ch, 10);
    if (!isNaN(code)) {
      const key = `${d.getFullYear()}${String(d.getMonth() + 1).padStart(2, "0")}${String(d.getDate()).padStart(2, "0")}`;
      data.set(key, code);
    }
  }
  return data;
}

export function loadCalendar(year: number): CalendarData {
  const digits = RAW[year];
  if (digits == null) throw new Error(`Нет фикстуры календаря за ${year}`);
  return parseRaw(year, digits as string);
}

export function loadCalendars(...years: number[]): Map<number, CalendarData> {
  const result = new Map<number, CalendarData>();
  for (const y of years) result.set(y, loadCalendar(y));
  return result;
}
